import{_ as e,o as i,c as a,ae as o}from"./chunks/framework.jfJLTIcL.js";const p=JSON.parse('{"title":"分支与发布规范","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/release-workflow.md","filePath":"zh-CN/release-workflow.md","lastUpdated":1775412435000}'),d={name:"zh-CN/release-workflow.md"};function c(t,l,r,s,n,h){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="分支与发布规范" tabindex="-1">分支与发布规范 <a class="header-anchor" href="#分支与发布规范" aria-label="Permalink to &quot;分支与发布规范&quot;">​</a></h1><p>这份文档定义的是 VILab 当前推荐的分支策略、发版节奏和公开发布仓的联动方式。</p><p>目标只有三个：</p><ul><li>日常开发和正式发布分离</li><li>私有源码仓和公开分发仓分离</li><li>每次正式发版都可以稳定更新官网、Release 和自动更新入口</li></ul><h2 id="推荐分支模型" tabindex="-1">推荐分支模型 <a class="header-anchor" href="#推荐分支模型" aria-label="Permalink to &quot;推荐分支模型&quot;">​</a></h2><ul><li><code>dev</code><ul><li>日常开发分支</li><li>新功能、重构、实验性调整先进入这里</li><li>可以保持较快迭代，不要求每次提交都可直接对外发布</li></ul></li><li><code>main</code><ul><li>稳定分支</li><li>只接收已经通过验证、准备进入正式版本的内容</li><li>目标是任何时刻都尽量保持“可发布”</li></ul></li></ul><p>对于当前项目，不建议一开始就引入额外的 <code>release/*</code> 分支。先保持 <code>dev + main</code> 两层结构，已经足够清晰。</p><h2 id="为什么不建议-合并到-main-就自动发版" tabindex="-1">为什么不建议“合并到 main 就自动发版” <a class="header-anchor" href="#为什么不建议-合并到-main-就自动发版" aria-label="Permalink to &quot;为什么不建议“合并到 main 就自动发版”&quot;">​</a></h2><p>看起来最省事的做法是：</p><ul><li><code>dev</code> 合并到 <code>main</code></li><li>GitHub Actions 自动发布安装包</li></ul><p>但这个模式实际风险比较高，因为“进入稳定分支”和“正式对外发布”并不是一回事。</p><p>常见问题包括：</p><ul><li>版本号还没准备好</li><li>release notes 还没写</li><li>还没完成最终回归测试</li><li>这批改动已经能进 <code>main</code>，但想和下一两个改动一起组成一个正式版本</li></ul><p>所以更推荐的方式是两段式：</p><ol><li><code>dev -&gt; main</code><ul><li>表示代码进入稳定候选区</li></ul></li><li>在 <code>main</code> 上打 <code>v0.1.7</code> 这样的 tag <ul><li>表示这次真的要发布</li></ul></li></ol><p>也就是说：</p><ul><li><code>main</code> 负责稳定</li><li><code>tag</code> 负责发布</li></ul><p>这是多数成熟项目更常见、也更稳的做法。</p><h2 id="推荐发布流程" tabindex="-1">推荐发布流程 <a class="header-anchor" href="#推荐发布流程" aria-label="Permalink to &quot;推荐发布流程&quot;">​</a></h2><h3 id="日常开发阶段" tabindex="-1">日常开发阶段 <a class="header-anchor" href="#日常开发阶段" aria-label="Permalink to &quot;日常开发阶段&quot;">​</a></h3><ul><li>功能开发先进入 <code>dev</code></li><li>在 <code>dev</code> 上完成联调、自测和必要的文档更新</li><li>功能达到稳定状态后，再合并到 <code>main</code></li></ul><h3 id="准备发布阶段" tabindex="-1">准备发布阶段 <a class="header-anchor" href="#准备发布阶段" aria-label="Permalink to &quot;准备发布阶段&quot;">​</a></h3><p>当你准备发布一个正式版本时，建议在 <code>main</code> 上完成以下内容：</p><ol><li>确认本次发布内容已经全部进入 <code>main</code></li><li>更新版本号</li><li>补齐对应的 release notes 文件</li><li>确认公开站点文案和文档已同步</li><li>打正式 tag，例如 <code>v0.1.7</code></li></ol><h3 id="正式发布阶段" tabindex="-1">正式发布阶段 <a class="header-anchor" href="#正式发布阶段" aria-label="Permalink to &quot;正式发布阶段&quot;">​</a></h3><p>当 tag 推送后，GitHub Actions 应触发正式发布流程，完成：</p><ul><li>构建安装包</li><li>生成签名与校验文件</li><li>生成 <code>latest.json</code></li><li>上传到公开仓 GitHub Release</li><li>更新公开站点中的下载入口和 changelog</li></ul><h2 id="当前项目中的职责分工" tabindex="-1">当前项目中的职责分工 <a class="header-anchor" href="#当前项目中的职责分工" aria-label="Permalink to &quot;当前项目中的职责分工&quot;">​</a></h2><h3 id="私有源码仓" tabindex="-1">私有源码仓 <a class="header-anchor" href="#私有源码仓" aria-label="Permalink to &quot;私有源码仓&quot;">​</a></h3><p>私有仓继续承担：</p><ul><li>源代码管理</li><li>日常开发与分支协作</li><li>文档源文件维护</li><li><code>.github/releases/*.md</code> 版本说明维护</li><li>构建、测试、发版 workflow</li></ul><h3 id="公开发布仓" tabindex="-1">公开发布仓 <a class="header-anchor" href="#公开发布仓" aria-label="Permalink to &quot;公开发布仓&quot;">​</a></h3><p>公开仓 <code>Ro-In-AI/VILab-public</code> 只承担公开分发：</p><ul><li>GitHub Releases</li><li>安装包与签名文件</li><li><code>latest.json</code></li><li>GitHub Pages 官网</li><li><code>/download/</code></li><li><code>/changelog/</code></li><li><code>/docs/</code></li></ul><h3 id="客户端自动更新" tabindex="-1">客户端自动更新 <a class="header-anchor" href="#客户端自动更新" aria-label="Permalink to &quot;客户端自动更新&quot;">​</a></h3><p>桌面应用内的 updater 固定读取公开仓：</p><ul><li><code>https://github.com/Ro-In-AI/VILab-public/releases/latest/download/latest.json</code></li></ul><p>因此，只要公开仓里的最新 Release 更新成功，客户端就能检测到新版本。</p><h2 id="推荐的-github-actions-触发方式" tabindex="-1">推荐的 GitHub Actions 触发方式 <a class="header-anchor" href="#推荐的-github-actions-触发方式" aria-label="Permalink to &quot;推荐的 GitHub Actions 触发方式&quot;">​</a></h2><h3 id="push-到-main" tabindex="-1"><code>push</code> 到 <code>main</code> <a class="header-anchor" href="#push-到-main" aria-label="Permalink to &quot;`push` 到 `main`&quot;">​</a></h3><p>建议只做“验证”和“站点内容同步”，不要直接发布正式版本。</p><p>适合做的事：</p><ul><li>安装依赖</li><li>类型检查</li><li>Rust 检查和测试</li><li>构建 docs</li><li>构建公开站点</li><li>同步公开站点内容</li></ul><p>不建议直接做的事：</p><ul><li>创建正式 GitHub Release</li><li>上传正式安装包</li><li>更新 <code>latest.json</code></li></ul><h3 id="push-tag-v" tabindex="-1"><code>push</code> tag <code>v*</code> <a class="header-anchor" href="#push-tag-v" aria-label="Permalink to &quot;`push` tag `v*`&quot;">​</a></h3><p>建议把正式发布动作全部放在 tag 触发下。</p><p>适合做的事：</p><ul><li>构建 Windows/macOS 安装包</li><li>上传公开仓 Release 资产</li><li>生成并上传 <code>latest.json</code></li><li>让客户端下载到新的正式版本</li></ul><p>这也是当前项目最推荐的正式发版入口。</p><h2 id="一次正式发版的标准步骤" tabindex="-1">一次正式发版的标准步骤 <a class="header-anchor" href="#一次正式发版的标准步骤" aria-label="Permalink to &quot;一次正式发版的标准步骤&quot;">​</a></h2><p>以下流程适合每次发版时照着执行。</p><ol><li>在 <code>dev</code> 完成功能开发和自测</li><li>将 <code>dev</code> 合并到 <code>main</code></li><li>切到 <code>main</code>，确认工作区干净</li><li>更新版本号</li><li>新建 release notes，例如 <code>.github/releases/v0.1.7.md</code></li><li>本地执行必要检查</li><li>提交版本相关改动到 <code>main</code></li><li>打 tag，例如 <code>v0.1.7</code></li><li>推送 <code>main</code> 和 <code>v0.1.7</code></li><li>观察 GitHub Actions 是否完成</li><li>到公开仓检查 Release、<code>latest.json</code>、下载页和 changelog</li></ol><h2 id="建议的本地发布检查清单" tabindex="-1">建议的本地发布检查清单 <a class="header-anchor" href="#建议的本地发布检查清单" aria-label="Permalink to &quot;建议的本地发布检查清单&quot;">​</a></h2><p>发版前至少确认下面这些项：</p><ul><li><code>package.json</code> 版本号正确</li><li><code>src-tauri/tauri.conf.json</code> 版本号正确</li><li><code>.github/releases/vX.Y.Z.md</code> 已存在</li><li>文档构建通过</li><li><code>public/docs</code> 和 <code>public/lab</code> 能正常生成</li><li>Windows 或 macOS 发布脚本本地检查通过</li><li>公开仓 secrets 没过期</li><li>Tauri updater 签名私钥已经配置到 GitHub secrets</li></ul><p>如果是正式外发版本，建议额外确认：</p><ul><li>安装包能正常安装</li><li>客户端能正常启动</li><li>自动更新说明显示正常</li><li><code>latest.json</code> 下载地址指向公开仓</li><li>Release 机器能正常生成 <code>.sig</code> 签名文件</li></ul><h2 id="当前项目建议采用的规则" tabindex="-1">当前项目建议采用的规则 <a class="header-anchor" href="#当前项目建议采用的规则" aria-label="Permalink to &quot;当前项目建议采用的规则&quot;">​</a></h2><p>为了降低误发版本的风险，建议固定采用下面这组规则：</p><ul><li>所有日常开发都先进入 <code>dev</code></li><li><code>main</code> 只合并准备进入正式版本的内容</li><li>合并到 <code>main</code> 不等于立即发版</li><li>只有打 tag 才算正式发版</li><li>正式版本号统一使用 <code>vX.Y.Z</code></li><li>release notes 统一写在 <code>.github/releases/</code></li><li>公开仓始终只承载正式稳定版本</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么热门开源仓也常用-tag-发布" tabindex="-1">为什么热门开源仓也常用 tag 发布 <a class="header-anchor" href="#为什么热门开源仓也常用-tag-发布" aria-label="Permalink to &quot;为什么热门开源仓也常用 tag 发布&quot;">​</a></h3><p>因为 tag 能明确表达“这次提交对应一个正式版本”，而不仅仅是某次普通合并。</p><p>相比“只要 main 更新就发布”，tag 发布的优点是：</p><ul><li>节奏可控</li><li>版本边界清楚</li><li>Release 页面天然和版本号一一对应</li><li>回滚、追踪和排错都更容易</li></ul><h3 id="是否需要-release-分支" tabindex="-1">是否需要 release 分支 <a class="header-anchor" href="#是否需要-release-分支" aria-label="Permalink to &quot;是否需要 release 分支&quot;">​</a></h3><p>当前阶段不需要。</p><p>如果未来出现这些情况，再考虑引入 <code>release/*</code>：</p><ul><li>同时维护多个长期版本</li><li>某个大版本需要长时间冻结和修补</li><li>商业版和社区版需要不同发布节奏</li></ul><p>在目前阶段，<code>dev + main + tag</code> 已经是成本最低、收益最高的方案。</p><h2 id="一句话结论" tabindex="-1">一句话结论 <a class="header-anchor" href="#一句话结论" aria-label="Permalink to &quot;一句话结论&quot;">​</a></h2><p>VILab 当前最推荐的发布策略是：</p><ul><li><code>dev</code> 负责开发</li><li><code>main</code> 负责稳定</li><li><code>tag</code> 负责正式发布</li><li>公开仓负责对外分发</li></ul><p>这样既能保持开发效率，也能让官网、下载入口、更新日志和客户端自动更新都围绕正式版本稳定运作。</p>',75)])])}const b=e(d,[["render",c]]);export{p as __pageData,b as default};
